    slug: 'witwenrente-rechner',
    letzteAktualisierung: '2026-06-24',
    titel: 'Witwenrente-Rechner',
    beschreibung: 'Witwenrente berechnen: Große und kleine Witwenrente, Einkommensanrechnung und Rentenanspruch.',
    kategorie: 'Finanzen',
